verify-multi-stage-flow.script:
test -f reports/prepare-workspace.txt || {
  echo '[ERROR] prepare-workspace marker missing'
  exit 1
}
test -f reports/lint-shell.txt || {
  echo '[ERROR] lint-shell marker missing'
  exit 1
}
test -f reports/unit-linux.txt || {
  echo '[ERROR] unit-linux marker missing'
  exit 1
}
test -f reports/unit-macos.txt || {
  echo '[ERROR] unit-macos marker missing'
  exit 1
}
test -f reports/package-bundle.txt || {
  echo '[ERROR] package-bundle marker missing'
  exit 1
}
grep -F 'prepare-workspace@prepare' reports/prepare-workspace.txt || {
  echo '[ERROR] prepare-workspace stage mismatch'
  exit 1
}
grep -F 'lint-shell@test' reports/lint-shell.txt || {
  echo '[ERROR] lint-shell stage mismatch'
  exit 1
}
grep -F 'unit-linux@test' reports/unit-linux.txt || {
  echo '[ERROR] unit-linux stage mismatch'
  exit 1
}
grep -F 'unit-macos@test' reports/unit-macos.txt || {
  echo '[ERROR] unit-macos stage mismatch'
  exit 1
}
grep -F 'package-bundle@package' reports/package-bundle.txt || {
  echo '[ERROR] package-bundle stage mismatch'
  exit 1
}
